#!/usr/bin/env python3
"""
CraneGenius Contact Intelligence — Self-Extracting Installer
Run from ~/Downloads/cranegenius_repo/:
    python3 install_contact_intelligence.py
"""
import base64, os
from pathlib import Path

REPO_ROOT = Path(__file__).parent
TARGET = REPO_ROOT / "contact_intelligence"

FILES = {
    "AGENT_CONTEXT.md": "",
    "CHANGELOG_AGENT.md": "",
    "TASK.md": "",
    "config/field_mappings.example.json": "",
    "docs/README.md": "",
    "docs/integration_notes.md": "",
    "requirements.txt": "b3BlbnB5eGw+PTMuMS4wCnJhcGlkZnV6ej49My4wLjAKcHl0aG9uLWRvdGVudj49MS4wLjAK",
    "sample_data/sample_contacts.csv": "",
    "sample_data/sample_seed.csv": "",
    "schema/create_tables.sql": "",
    "schema/indexes.sql": "",
    "schema/seed_sectors.sql": "",
    "scripts/backup_db.py": "",
    "scripts/dedupe_people_companies.py": "",
    "scripts/export_views.py": "",
    "scripts/import_csv.py": "",
    "scripts/import_seed_data.py": "",
    "scripts/init_db.py": "",
    "scripts/log_feedback.py": "",
    "scripts/normalize_records.py": "",
    "scripts/run_gold_truth_checks.py": "",
    "scripts/score_domain_evidence.py": "",
    "scripts/search_cli.py": "",
    "scripts/update_contact_patterns.py": "",
}

def install():
    created = 0
    for rel_path, b64 in FILES.items():
        dest = TARGET / rel_path
        dest.parent.mkdir(parents=True, exist_ok=True)
        dest.write_bytes(base64.b64decode(b64))
        print(f"  [+] {rel_path}")
        created += 1
    print(f"\n✓ Installed {created} files to {TARGET}")
    print("\nNext step:")
    print("  python3 contact_intelligence/scripts/init_db.py")

if __name__ == "__main__":
    install()